"""Contract test for the checked-in OpenAPI spec (agent/openapi.json, generated by
scripts/export_openapi.py) -- no live server, no network. Guards against the checked-in spec
silently drifting out of sync with the actual FastAPI app (e.g. an endpoint added/removed/renamed
without regenerating the spec, which would mislead anyone integrating against the committed file).
"""
from __future__ import annotations

import json
import os

from app.main import app

OPENAPI_JSON_PATH = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "openapi.json")

EXPECTED_ENDPOINTS = {
    ("/health", "get"),
    ("/ready", "get"),
    ("/chat", "post"),
    ("/ingest", "post"),
}


def _load_checked_in_spec() -> dict:
    with open(OPENAPI_JSON_PATH, "r", encoding="utf-8") as f:
        return json.load(f)


def test_checked_in_spec_matches_the_live_app_exactly():
    """Failure mode guarded: someone edits an endpoint in app/main.py and forgets to re-run
    scripts/export_openapi.py -- the committed spec would silently describe an API that no longer
    exists. Regenerating and comparing catches that immediately."""
    checked_in = _load_checked_in_spec()
    live = app.openapi()

    assert checked_in == live, (
        "agent/openapi.json is stale -- run `python scripts/export_openapi.py` from agent/ and commit the diff."
    )


def test_all_expected_endpoints_are_present():
    spec = _load_checked_in_spec()
    actual = {(path, method) for path, methods in spec["paths"].items() for method in methods}

    missing = EXPECTED_ENDPOINTS - actual
    assert not missing, f"expected endpoints missing from the spec: {missing}"


def test_chat_endpoint_documents_its_response_model():
    spec = _load_checked_in_spec()
    responses = spec["paths"]["/chat"]["post"]["responses"]
    assert "200" in responses
    schema = responses["200"]["content"]["application/json"]["schema"]
    assert "$ref" in schema or "properties" in schema, "chat's 200 response has no documented schema"


def test_ingest_endpoint_accepts_multipart_form_data():
    """Boundary: /ingest takes a file upload (multipart), not JSON -- the spec must reflect that,
    since a client generating code from this spec needs to know to send multipart, not JSON."""
    spec = _load_checked_in_spec()
    request_body = spec["paths"]["/ingest"]["post"]["requestBody"]
    assert "multipart/form-data" in request_body["content"]
